class DecoderBlock(nn.Module):
    def __init__(self, d, h):
        super().__init__()
        self.self_attn  = Attention(d, h)
        self.cross_attn = Attention(d, h)
        self.ff = nn.Sequential(nn.Linear(d, 4*d), nn.ReLU(), nn.Linear(4*d, d))
    def forward(self, y, memory, causal):
        y = y + self.self_attn(y, y, causal)[0]      # self
        y = y + self.cross_attn(y, memory)[0]        # cross
        return y + self.ff(y)
